[FormDataSourceEventHandler(formDataSourceStr(PurchTable, PurchLine), FormDataSourceEventType::Written)]
public static void PurchLine_OnWritten(FormDataSource sender, FormDataSourceEventArgs e)
{
    PurchLine purchline      =  sender.cursor();

    ETG_PurchLineNotes            purchLineNotes;
    ETGTradingNotes               tradingNotes;
    ETG_PurchLineQualityGrp       purchLineQualityGrp;
    ETG_ProductReceiptQualityGrp  productReceiptQualityGrp;
    ETG_ItemQualityGrp            itemQualityGrp;
    ETG_ItemQualitySpecDetails    itemQualitySpecDetails;

    RecordInsertList        tmpInsNotes       = new RecordInsertList(tableNum(ETG_PurchLineNotes));
    RecordInsertList        tmpInsSpecGrp     = new RecordInsertList(tableNum(ETG_PurchLineQualityGrp));
    RecordInsertList        tmpInsSpecDetails = new RecordInsertList(tableNum(ETG_ProductReceiptQualityGrp));

    delete_from purchLineNotes
        where purchLineNotes.InventTransId == purchline.InventTransId;

    while select EnumNotes,Description from tradingNotes
        where tradingNotes.ItemId == purchline.ItemId
    {
        purchLineNotes.InventTransId = purchline.InventTransId;
        purchLineNotes.EnumNotes     = tradingNotes.EnumNotes;
        purchLineNotes.Description   = tradingNotes.Description;
        purchLineNotes.ItemId        = purchline.ItemId;
        tmpInsNotes.add(purchLineNotes);
    }        

    delete_from purchLineQualityGrp
       where purchLineQualityGrp.InventTransId == purchline.InventTransId;

    while select * from itemQualityGrp
        where itemQualityGrp.ItemId  == purchline.ItemId
    {
        purchLineQualityGrp.GroupId         = itemQualityGrp.GroupId;
        purchLineQualityGrp.InventTransId   = purchline.InventTransId;
        tmpInsSpecGrp.add(purchLineQualityGrp);
    }

    while select * from itemQualitySpecDetails
         where itemQualitySpecDetails.ItemId == purchline.ItemId
    {
        productReceiptQualityGrp.GroupID               = itemQualitySpecDetails.GroupID;
        productReceiptQualityGrp.MaxRange              = itemQualitySpecDetails.MaxRange;
        productReceiptQualityGrp.MinRange              = itemQualitySpecDetails.MinRange;
        productReceiptQualityGrp.InventTransId         = purchline.InventTransId;
        productReceiptQualityGrp.PurchId               = purchline.PurchId;
        productReceiptQualityGrp.SubGroupId            = itemQualitySpecDetails.SubGrpId;
        productReceiptQualityGrp.SubGroupDescription   = itemQualitySpecDetails.SubGroupDescription;
        productReceiptQualityGrp.MeasurementType       = itemQualitySpecDetails.MeasurementType;
        productReceiptQualityGrp.AdjustmentType        = itemQualitySpecDetails.AdjustmentType;
        productReceiptQualityGrp.Increment             = itemQualitySpecDetails.Increment;
        productReceiptQualityGrp.FixedValue            = itemQualitySpecDetails.FixedValue;
        tmpInsSpecDetails.add(productReceiptQualityGrp);
    }

    tmpInsNotes.insertDatabase();
    tmpInsSpecGrp.insertDatabase();
    tmpInsSpecDetails.insertDatabase();

}

[FormDataSourceEventHandler(formDataSourceStr(SalesTable, SalesLine), FormDataSourceEventType::Written)]
public static void SalesLine_OnWritten(FormDataSource sender, FormDataSourceEventArgs e)
{
    SalesLine salesLine      =  sender.cursor();

    ETG_SalesLineNotes            salesLineNotes;
    ETGTradingNotes               tradingNotes;
    ETG_SalesLineQualityGrp       salesLineQualityGrp;
    ETG_PostPackingQualityGrp     productReceiptQualityGrp;
    ETG_ItemQualityGrp            itemQualityGrp;
    ETG_ItemQualitySpecDetails    itemQualitySpecDetails;

    RecordInsertList        tmpInsNotes       = new RecordInsertList(tableNum(ETG_SalesLineNotes));
    RecordInsertList        tmpInsSpecGrp     = new RecordInsertList(tableNum(ETG_SalesLineQualityGrp));
    RecordInsertList        tmpInsSpecDetails = new RecordInsertList(tableNum(ETG_PostPackingQualityGrp));

    delete_from salesLineNotes
        where salesLineNotes.InventTransId == salesline.InventTransId;

    while select EnumNotes,Description from tradingNotes
        where tradingNotes.ItemId == salesline.ItemId
    {
        salesLineNotes.InventTransId = salesline.InventTransId;
        salesLineNotes.EnumNotes     = tradingNotes.EnumNotes;
        salesLineNotes.Description   = tradingNotes.Description;
        salesLineNotes.ItemId        = salesline.ItemId;
        tmpInsNotes.add(salesLineNotes);
    }


    delete_from salesLineQualityGrp
        where salesLineQualityGrp.InventTransId == salesline.InventTransId;

    while select * from itemQualityGrp
        where itemQualityGrp.ItemId  == salesline.ItemId
    {
        salesLineQualityGrp.GroupId         = itemQualityGrp.GroupId;
        salesLineQualityGrp.InventTransId   = salesline.InventTransId;
        tmpInsSpecGrp.add(salesLineQualityGrp);
    }

    while select * from itemQualitySpecDetails
         where itemQualitySpecDetails.ItemId == salesline.ItemId
    {
        productReceiptQualityGrp.GroupID               = itemQualitySpecDetails.GroupID;
        productReceiptQualityGrp.MaxRange              = itemQualitySpecDetails.MaxRange;
        productReceiptQualityGrp.MinRange              = itemQualitySpecDetails.MinRange;
        productReceiptQualityGrp.InventTransId         = salesline.InventTransId;
        productReceiptQualityGrp.SalesId               = salesline.SalesId;
        productReceiptQualityGrp.SubGroupId            = itemQualitySpecDetails.SubGrpId;
        productReceiptQualityGrp.SubGroupDescription   = itemQualitySpecDetails.SubGroupDescription;
        productReceiptQualityGrp.MeasurementType       = itemQualitySpecDetails.MeasurementType;
        productReceiptQualityGrp.AdjustmentType        = itemQualitySpecDetails.AdjustmentType;
        productReceiptQualityGrp.Increment             = itemQualitySpecDetails.Increment;
        productReceiptQualityGrp.FixedValue            = itemQualitySpecDetails.FixedValue;
        tmpInsSpecDetails.add(productReceiptQualityGrp);
    }

    tmpInsNotes.insertDatabase();
    tmpInsSpecGrp.insertDatabase();
    tmpInsSpecDetails.insertDatabase();

}
